"use strict";(self.webpackChunkauctions_for_woocommerce_doc=self.webpackChunkauctions_for_woocommerce_doc||[]).push([[3976],{8031(e,t,r){r.r(t),r.d(t,{comp:()=>o,data:()=>n});var a=r(641);const i={},o=(0,r(6262).A)(i,[["render",function(e,t){return(0,a.uX)(),(0,a.CE)("div",null,[...t[0]||(t[0]=[(0,a.Fv)('<h1 id="pending-review" tabindex="-1"><a class="header-anchor" href="#pending-review"><span>Pending Review</span></a></h1><p><strong>Auctions → Pending Review</strong> — <code>?page=wkafw-pending-review</code></p><p>Vendor lot moderation queue. When <code>wkafw_lot_review_enabled = yes</code>, every auction created by a vendor enters a pending state until an admin approves it. This page is the approval queue.</p><p><img src="/auctions-for-woocommerce/images/screenshots/admin-pending-review.png" alt="Pending Review — vendor lot moderation queue with approve / reject / request-changes actions"></p><h2 id="when-is-this-needed" tabindex="-1"><a class="header-anchor" href="#when-is-this-needed"><span>When is this needed?</span></a></h2><p>Only when you have:</p><ul><li>A multi-vendor marketplace (<a href="/multi-vendor.html" target="_blank" rel="noopener noreferrer">WCFM, Dokan, WC Vendors, YITH</a>)</li><li>Vendor-created auctions (vs admin-curated)</li><li>Quality / compliance gating before lots go live</li></ul><p>For single-vendor stores, lot review can stay off — admins create lots directly.</p><h2 id="enabling-lot-review" tabindex="-1"><a class="header-anchor" href="#enabling-lot-review"><span>Enabling lot review</span></a></h2><p><strong>Auctions → Settings → Bidding → Require admin approval for vendor lots</strong> (<code>wkafw_lot_review_enabled = yes</code>).</p><p>When enabled:</p><ul><li>Every vendor-saved auction starts as <code>status = pending</code></li><li>Lot is invisible to bidders</li><li>An entry appears here</li><li>Vendor sees &quot;Awaiting review&quot; on their dashboard</li><li>Admin must approve / reject before lot goes live</li></ul><h2 id="page-layout" tabindex="-1"><a class="header-anchor" href="#page-layout"><span>Page layout</span></a></h2><table><thead><tr><th>Column</th><th>Source</th></tr></thead><tbody><tr><td>ID</td><td>auction ID</td></tr><tr><td>Title</td><td>linked product title</td></tr><tr><td>Vendor</td><td>vendor name + WC store link</td></tr><tr><td>Type</td><td>auction type</td></tr><tr><td>Start price</td><td>currency</td></tr><tr><td>Reserve</td><td>currency / not set</td></tr><tr><td>Submitted</td><td>timestamp</td></tr><tr><td>Time waiting</td><td>hours / days</td></tr><tr><td>Actions</td><td>Approve / Reject / Edit</td></tr></tbody></table><p>Filter by vendor, age (waiting &gt; 24 hrs), or auction type.</p><h2 id="per-row-actions" tabindex="-1"><a class="header-anchor" href="#per-row-actions"><span>Per-row actions</span></a></h2><h3 id="approve" tabindex="-1"><a class="header-anchor" href="#approve"><span>Approve</span></a></h3><ol><li>Click <strong>Approve</strong></li><li>Lot status flips to <code>scheduled</code> (or <code>active</code> if start date is past)</li><li>Vendor receives <strong>Lot Approved</strong> email</li><li>Lot becomes visible on storefront</li></ol><h3 id="reject" tabindex="-1"><a class="header-anchor" href="#reject"><span>Reject</span></a></h3><ol><li>Click <strong>Reject</strong></li><li>Modal asks for <strong>Rejection reason</strong> (required, vendor-visible)</li><li>Lot status flips to <code>rejected</code></li><li>Vendor receives <strong>Lot Rejected</strong> email with reason</li><li>Vendor can edit and resubmit</li></ol><h3 id="edit" tabindex="-1"><a class="header-anchor" href="#edit"><span>Edit</span></a></h3><p>Opens <a href="/admin-add-auction.html" target="_blank" rel="noopener noreferrer">Add / Edit Auction</a> — admin can adjust pricing, schedule, images before approving.</p><h2 id="bulk-actions" tabindex="-1"><a class="header-anchor" href="#bulk-actions"><span>Bulk actions</span></a></h2><table><thead><tr><th>Action</th><th>Effect</th></tr></thead><tbody><tr><td><strong>Approve all selected</strong></td><td>Mass-approve (skip if individual review needed)</td></tr><tr><td><strong>Reject all selected</strong></td><td>Mass-reject — single shared reason</td></tr><tr><td><strong>Assign to me</strong></td><td>Take ownership; other admins see &quot;claimed&quot;</td></tr></tbody></table><h2 id="drawer-view" tabindex="-1"><a class="header-anchor" href="#drawer-view"><span>Drawer view</span></a></h2><p>Click the row to expand the full submission:</p><ul><li>Auction config (start price, reserve, schedule)</li><li>Linked product details (description, images, condition)</li><li>Vendor history (past lots, approval rate, dispute rate)</li><li>Recent admin notes</li><li>Compliance flags (age-gated category, KYC needed, etc.)</li></ul><h2 id="sla-tracking" tabindex="-1"><a class="header-anchor" href="#sla-tracking"><span>SLA tracking</span></a></h2><p>Configurable thresholds in <strong>Auctions → Settings → Bidding</strong>:</p><table><thead><tr><th>Threshold</th><th>Default</th><th>Effect</th></tr></thead><tbody><tr><td>Yellow</td><td>4 hrs</td><td>Row highlighted yellow</td></tr><tr><td>Red</td><td>24 hrs</td><td>Row highlighted red, admin email digest fires</td></tr></tbody></table><p>The daily admin digest email lists every red-state lot.</p><h2 id="auto-approve-rules" tabindex="-1"><a class="header-anchor" href="#auto-approve-rules"><span>Auto-approve rules</span></a></h2><p>For trusted vendors, set <strong>Auto-approve threshold</strong>:</p><ul><li>Vendor&#39;s past N lots (default 10) all approved</li><li>0 disputes in last 90 days</li><li>Compliance flags clean</li></ul><p>When met, future lots skip review automatically (lot status → <code>scheduled</code>). Override per-vendor on the vendor&#39;s profile page.</p><h2 id="compliance-flags" tabindex="-1"><a class="header-anchor" href="#compliance-flags"><span>Compliance flags</span></a></h2><p>The queue auto-flags lots that hit any of:</p><table><thead><tr><th>Flag</th><th>Trigger</th></tr></thead><tbody><tr><td><strong>Age-gated</strong></td><td>Product is in <code>wkafw_age_gated_categories</code></td></tr><tr><td><strong>KYC needed</strong></td><td>Reserve &gt; <code>wkafw_kyc_threshold</code> and vendor not KYC&#39;d</td></tr><tr><td><strong>High-risk category</strong></td><td>Product is in admin-defined risk list</td></tr><tr><td><strong>First-time vendor</strong></td><td>Vendor has no past approved lots</td></tr><tr><td><strong>Returned-vendor</strong></td><td>Vendor was previously suspended</td></tr></tbody></table><p>Flags appear as chips next to the lot. Admins should review flagged lots more carefully.</p><h2 id="reporting" tabindex="-1"><a class="header-anchor" href="#reporting"><span>Reporting</span></a></h2><p><a href="/admin-reports.html" target="_blank" rel="noopener noreferrer">Reports → Lot review</a> shows:</p><ul><li>Approval rate per vendor</li><li>Median time to approval</li><li>Rejection reasons (top categories)</li><li>Re-submission rate</li></ul><h2 id="common-workflows" tabindex="-1"><a class="header-anchor" href="#common-workflows"><span>Common workflows</span></a></h2><h3 id="triaging-the-daily-backlog" tabindex="-1"><a class="header-anchor" href="#triaging-the-daily-backlog"><span>Triaging the daily backlog</span></a></h3><ol><li>Sort by <strong>Time waiting</strong> descending</li><li>Approve trusted-vendor lots in bulk</li><li>Drill into flagged lots individually</li><li>Reject duplicates or non-compliant lots with clear reasons</li></ol><h3 id="onboarding-a-new-vendor" tabindex="-1"><a class="header-anchor" href="#onboarding-a-new-vendor"><span>Onboarding a new vendor</span></a></h3><ol><li>Their first 10 lots queue here for manual review</li><li>After 10 clean approvals, auto-approve threshold kicks in</li><li>Audit periodically — pull the vendor&#39;s row out of <a href="/admin-reports.html" target="_blank" rel="noopener noreferrer">Reports → Lot review</a></li></ol><h3 id="spot-checking-auto-approved-lots" tabindex="-1"><a class="header-anchor" href="#spot-checking-auto-approved-lots"><span>Spot-checking auto-approved lots</span></a></h3><p>Even with auto-approve, you can spot-check:</p><ol><li><strong>All Auctions → filter by status: scheduled, vendor created</strong></li><li>Sample 5 random lots</li><li>Review for compliance / quality</li></ol>',50)])])}]]),n=JSON.parse('{"path":"/admin-pending-review.html","title":"Pending Review","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"When is this needed?","slug":"when-is-this-needed","link":"#when-is-this-needed","children":[]},{"level":2,"title":"Enabling lot review","slug":"enabling-lot-review","link":"#enabling-lot-review","children":[]},{"level":2,"title":"Page layout","slug":"page-layout","link":"#page-layout","children":[]},{"level":2,"title":"Per-row actions","slug":"per-row-actions","link":"#per-row-actions","children":[{"level":3,"title":"Approve","slug":"approve","link":"#approve","children":[]},{"level":3,"title":"Reject","slug":"reject","link":"#reject","children":[]},{"level":3,"title":"Edit","slug":"edit","link":"#edit","children":[]}]},{"level":2,"title":"Bulk actions","slug":"bulk-actions","link":"#bulk-actions","children":[]},{"level":2,"title":"Drawer view","slug":"drawer-view","link":"#drawer-view","children":[]},{"level":2,"title":"SLA tracking","slug":"sla-tracking","link":"#sla-tracking","children":[]},{"level":2,"title":"Auto-approve rules","slug":"auto-approve-rules","link":"#auto-approve-rules","children":[]},{"level":2,"title":"Compliance flags","slug":"compliance-flags","link":"#compliance-flags","children":[]},{"level":2,"title":"Reporting","slug":"reporting","link":"#reporting","children":[]},{"level":2,"title":"Common workflows","slug":"common-workflows","link":"#common-workflows","children":[{"level":3,"title":"Triaging the daily backlog","slug":"triaging-the-daily-backlog","link":"#triaging-the-daily-backlog","children":[]},{"level":3,"title":"Onboarding a new vendor","slug":"onboarding-a-new-vendor","link":"#onboarding-a-new-vendor","children":[]},{"level":3,"title":"Spot-checking auto-approved lots","slug":"spot-checking-auto-approved-lots","link":"#spot-checking-auto-approved-lots","children":[]}]}],"git":{},"filePathRelative":"admin-pending-review.md"}')}}]);